ما هو التعقيد الزمني لهذا الكود؟

int x = arr[5];
cout << x;

ما التعقيد الزمني للدالة العودية التالية؟

int fib(int n) {
    if (n <= 1) return n;
    return fib(n-1) + fib(n-2);
}

ما التعقيد الزمني لهذا الكود؟

for (int i = 0; i < n; i++) {
    for (int j = 0; j < n; j++) {
        for (int k = 0; k < n; k++) {
            cout << i + j + k;
        }
    }
}

